/// Look up a Pentax model ID against `%pentaxModelID`. Returns the body name,
/// or `None` when the ID is absent (ExifTool then renders the bare `0xNNNN`
/// hex via `PrintHex => 1`).
#[must_use]
pub fn lookup_name(id: u32) -> Option<SmolStr> {
  match PENTAX_MODEL_IDS.binary_search_by_key(&id, |&(k, _)| k) {
    Ok(i) => PENTAX_MODEL_IDS
      .get(i)
      .map(|&(_, name)| SmolStr::from(name)),
    Err(_) => None,
  }
}

